import{c as a,Q as r,j as e,m as l}from"./chunks/framework.BIBjCrbN.js";const b=JSON.parse('{"title":"上海交通大学","description":"上海交通大学生物医学工程学院博士项目指南 — 导师信息、申请流程与2027年入学关键节点","frontmatter":{"title":"上海交通大学","description":"上海交通大学生物医学工程学院博士项目指南 — 导师信息、申请流程与2027年入学关键节点","data-collected":"2026-05-25T00:00:00.000Z","related-directions":["bci","bme","neuroscience","medical-physics"],"tags":["上海交通大学","上海",985,"C9"],"admission-year":2027},"headers":[],"relativePath":"universities/sjtu.md","filePath":"universities/sjtu.md","lastUpdated":1780110618000}'),o={name:"universities/sjtu.md"};function i(d,t,n,s,h,u){return r(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="上海交通大学" tabindex="-1">上海交通大学 <a class="header-anchor" href="#上海交通大学" aria-label="Permalink to &quot;上海交通大学&quot;">​</a></h1><blockquote><p><strong>最后更新</strong>: 2026年5月25日</p></blockquote><h2 id="学校概况" tabindex="-1">学校概况 <a class="header-anchor" href="#学校概况" aria-label="Permalink to &quot;学校概况&quot;">​</a></h2><p>上海交通大学生物医学工程学科为国家一级重点学科，在2025年QS学科排名中位列全国前3。学院拥有生物医学工程一级学科博士点，与多家附属医院共建&quot;医工交叉平台&quot;，产学研结合紧密。</p><p><strong>官方链接</strong>:</p><ul><li>学校官网: <a href="https://www.sjtu.edu.cn" target="_blank" rel="noreferrer">https://www.sjtu.edu.cn</a></li><li>研究生招生网: <a href="https://yzb.sjtu.edu.cn" target="_blank" rel="noreferrer">https://yzb.sjtu.edu.cn</a></li><li>生物医学工程学院: <a href="https://bme.sjtu.edu.cn" target="_blank" rel="noreferrer">https://bme.sjtu.edu.cn</a></li><li>2026年博士招生办法: <a href="https://bme.sjtu.edu.cn/Web/Show/4053" target="_blank" rel="noreferrer">学院招生页面</a></li></ul><h2 id="招生专业" tabindex="-1">招生专业 <a class="header-anchor" href="#招生专业" aria-label="Permalink to &quot;招生专业&quot;">​</a></h2><table tabindex="0"><thead><tr><th>学位类别</th><th>专业代码</th><th>专业名称</th><th>培养方式</th></tr></thead><tbody><tr><td>学术型博士</td><td>071000</td><td>生物学</td><td>全日制</td></tr><tr><td>学术型博士</td><td>083100</td><td>生物医学工程</td><td>全日制</td></tr><tr><td>工程博士</td><td>085400</td><td>电子信息</td><td>全日制</td></tr><tr><td>工程博士</td><td>086000</td><td>生物与医药</td><td>全日制</td></tr></tbody></table><hr><h2 id="_2026年博士招生-—-申请-考核-制" tabindex="-1">2026年博士招生 — &quot;申请-考核&quot;制 <a class="header-anchor" href="#_2026年博士招生-—-申请-考核-制" aria-label="Permalink to &quot;2026年博士招生 — &quot;申请-考核&quot;制&quot;">​</a></h2><h3 id="申请条件" tabindex="-1">申请条件 <a class="header-anchor" href="#申请条件" aria-label="Permalink to &quot;申请条件&quot;">​</a></h3><h4 id="基本要求" tabindex="-1">基本要求 <a class="header-anchor" href="#基本要求" aria-label="Permalink to &quot;基本要求&quot;">​</a></h4><p>符合《上海交通大学2026年博士研究生招生简章（校本部）》规定的申请条件。</p><h4 id="英语水平要求" tabindex="-1">英语水平要求 <a class="header-anchor" href="#英语水平要求" aria-label="Permalink to &quot;英语水平要求&quot;">​</a></h4><p>成绩须为2020年1月1日之后取得，满足其一即可：</p><ul><li>全国大学英语六级成绩 <strong>≥ 425分</strong></li><li>新TOEFL <strong>≥ 90分</strong></li><li>IELTS <strong>≥ 6.0分</strong></li><li>参加全英文授课学位项目并获得学位 ✅（你符合此项：Imperial College + UCL均为全英文授课）</li></ul><h4 id="学术背景要求-满足下述条件之一" tabindex="-1">学术背景要求（满足下述条件之一） <a class="header-anchor" href="#学术背景要求-满足下述条件之一" aria-label="Permalink to &quot;学术背景要求（满足下述条件之一）&quot;">​</a></h4><ol><li>申请人来自**&quot;双一流&quot;高校**或&quot;双一流&quot;学科或学科为原国家重点学科</li><li>申请人获得境外文凭的学校为<strong>国际排名前200</strong>的学校 ✅（你符合此项：Imperial College + UCL均在全球前200）</li><li>申请人来自<strong>中国科学院及中国工程院所属科研院所</strong>或国家重点实验室</li><li>申请人在硕士阶段以<strong>第一作者</strong>在学科方向排名前30%的杂志上发表过SCI论文，并经申请人所在学院院长推荐</li><li>申请人具有突出创新能力和特殊学术专长</li></ol><blockquote><p>你的Imperial College硕士背景同时满足条件1和条件2。</p></blockquote><h3 id="申请时间" tabindex="-1">申请时间 <a class="header-anchor" href="#申请时间" aria-label="Permalink to &quot;申请时间&quot;">​</a></h3><blockquote><p><strong>2025年11月1日 - 2025年11月30日</strong>（2027级入学批次，已关闭）</p></blockquote><h3 id="申请材料" tabindex="-1">申请材料 <a class="header-anchor" href="#申请材料" aria-label="Permalink to &quot;申请材料&quot;">​</a></h3><ol><li>《上海交通大学博士学位研究生报考登记表》及身份证复印件</li><li>成绩单原件（加盖公章）</li><li>外语水平证明材料</li><li>获奖证书复印件（如有）</li><li>科研成果、公开发表的学术论文或专著等复印件（如有）</li><li><strong>两封推荐信</strong>（一封由硕士生导师提供，一封由本学科副高以上职称专家提供）</li><li>硕士学位论文摘要和目录</li><li><strong>拟攻读博士学位的科学研究计划书</strong>（必须提供）</li><li>学历、学位证书及认证报告</li></ol><h3 id="综合考核-总分300分" tabindex="-1">综合考核（总分300分） <a class="header-anchor" href="#综合考核-总分300分" aria-label="Permalink to &quot;综合考核（总分300分）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>考核模块</th><th>分值</th><th>形式</th><th>内容</th></tr></thead><tbody><tr><td><strong>专业测试</strong></td><td>100分</td><td>笔试（3小时）</td><td>专业基础和知识结构</td></tr><tr><td><strong>综合面试</strong></td><td>100分</td><td>面试（10-15分钟PPT汇报）</td><td>知识背景、科研能力、外语水平、综合能力</td></tr><tr><td><strong>导师（组）评价</strong></td><td>100分</td><td>导师组考察</td><td>专业水平、从事科研的能力和培养前景</td></tr></tbody></table><h4 id="专业测试科目-按领域分类" tabindex="-1">专业测试科目（按领域分类） <a class="header-anchor" href="#专业测试科目-按领域分类" aria-label="Permalink to &quot;专业测试科目（按领域分类）&quot;">​</a></h4><table tabindex="0"><thead><tr><th>领域</th><th>可选科目</th></tr></thead><tbody><tr><td><strong>生物方向</strong></td><td>①生物化学 ②细胞生物学（二选一）</td></tr><tr><td><strong>纳米、分子及再生医学</strong></td><td>纳米诊断技术</td></tr><tr><td><strong>生物医疗仪器</strong></td><td>①仪器科学与技术综合原理 ②生物医学信号处理 ③传热学与流体力学（三选一）</td></tr><tr><td><strong>影像、计算及系统生物学</strong></td><td>①工程数学与工程力学 ②计算机科学与技术综合测试 ③数字图像处理 ④光学成像（四选一）</td></tr></tbody></table><blockquote><p>对你的背景，建议选择<strong>生物医疗仪器</strong>方向的&quot;生物医学信号处理&quot;或<strong>影像/计算</strong>方向的科目。</p></blockquote><h3 id="录取原则" tabindex="-1">录取原则 <a class="header-anchor" href="#录取原则" aria-label="Permalink to &quot;录取原则&quot;">​</a></h3><ul><li>按综合考核成绩从高分到低分依次拟录取</li><li>单科成绩不合格（低于60分）或总分不合格（低于180分）者不予录取</li><li>通过考核者可选择<strong>春季或秋季</strong>入学</li></ul><h3 id="医工交叉平台" tabindex="-1">医工交叉平台 <a class="header-anchor" href="#医工交叉平台" aria-label="Permalink to &quot;医工交叉平台&quot;">​</a></h3><p>上交还设有**&quot;医工交叉平台&quot;博士研究生专项计划**，2026年采用本科直博方式招生，涵盖生医工学院与多家附属医院的交叉方向，实行双导师制，学制5年。</p><hr><h2 id="重点课题组与导师" tabindex="-1">重点课题组与导师 <a class="header-anchor" href="#重点课题组与导师" aria-label="Permalink to &quot;重点课题组与导师&quot;">​</a></h2><h3 id="——-神经工程-脑机接口方向-——" tabindex="-1">—— 神经工程 / 脑机接口方向 —— <a class="header-anchor" href="#——-神经工程-脑机接口方向-——" aria-label="Permalink to &quot;—— 神经工程 / 脑机接口方向 ——&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">待完善</p><p>上交生医工学院神经工程方向的导师信息正在收集中。该学院在<strong>生物医疗仪器</strong>和<strong>医学影像</strong>方向师资力量强大。</p></div><h3 id="——-生物医学工程核心方向-——" tabindex="-1">—— 生物医学工程核心方向 —— <a class="header-anchor" href="#——-生物医学工程核心方向-——" aria-label="Permalink to &quot;—— 生物医学工程核心方向 ——&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">收集建议</p><p>建议重点浏览 <a href="https://bme.sjtu.edu.cn/Web/Faculty" target="_blank" rel="noreferrer">上交BME师资页面</a> 获取完整的导师列表和研究方向。</p></div><hr><h2 id="针对你的申请建议" tabindex="-1">针对你的申请建议 <a class="header-anchor" href="#针对你的申请建议" aria-label="Permalink to &quot;针对你的申请建议&quot;">​</a></h2><ol><li><strong>英语要求已轻松达标</strong>：你的英本+英硕背景自动满足&quot;全英文授课学位项目&quot;条件</li><li><strong>学术背景条件已满足</strong>：Imperial College全球前200 + UCL全球前200</li><li><strong>研究计划书至关重要</strong>：上交要求必须提供，建议针对目标导师方向精心打磨</li><li><strong>笔试需准备</strong>：选择与你背景匹配的科目（生物医学信号处理或光学成像）</li><li><strong>关注医工交叉平台</strong>：如有硬件+生物结合的课题，双导师制是不错的选择</li></ol><hr><h2 id="信息来源" tabindex="-1">信息来源 <a class="header-anchor" href="#信息来源" aria-label="Permalink to &quot;信息来源&quot;">​</a></h2><ul><li><a href="https://bme.sjtu.edu.cn/Web/Show/4053" target="_blank" rel="noreferrer">上交BME学院招生办法</a> — 2026年申请考核制招生（访问日期: 2026-05-25）</li><li><a href="https://yzb.sjtu.edu.cn/" target="_blank" rel="noreferrer">上海交大研招网</a> — 研究生招生信息（访问日期: 2026-05-25）</li></ul><hr><p><em>本页面信息采集于2026年5月，请以上海交通大学研究生院官网最新公告为准。</em></p><p><em>下次更新建议: 2026年8月</em></p>',47)])])}const g=a(o,[["render",i]]);export{b as __pageData,g as default};
